using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "which", "who", "whom", "what", "where", "when",
        "how", "not", "no", "do", "does", "did", "has", "have", "had",
        "be", "been", "being", "will", "would", "could", "should", "may",
        "might", "shall", "can", "as", "if", "then", "than", "so", "such"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
        {
            return string.Join(" ", sentences);
        }

        var wordFrequencies = ComputeWordFrequencies(documentText);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i) // preserve original order
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]);
        return string.Join(" ", summarySentences);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(string text)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var words = WordTokenizer().Matches(text);

        foreach (Match match in words)
        {
            var word = match.Value;
            if (word.Length < 2 || StopWords.Contains(word))
                continue;

            frequencies.TryGetValue(word, out int count);
            frequencies[word] = count + 1;
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);
        var maxFrequency = wordFrequencies.Values.DefaultIfEmpty(1).Max();

        foreach (var sentence in sentences)
        {
            var words = WordTokenizer().Matches(sentence);
            double score = 0;
            int wordCount = 0;

            foreach (Match match in words)
            {
                wordCount++;
                if (wordFrequencies.TryGetValue(match.Value, out int freq))
                {
                    score += (double)freq / maxFrequency;
                }
            }

            scores.Add(wordCount > 0 ? score / wordCount : 0);
        }

        return scores;
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordTokenizer();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

